"use client";

import { useState, useEffect } from "react";
import { fetchAirQuality } from "../lib/fetchAirQuality";
import { cityMapping } from "../lib/cityMapping";

export function useAQIData() {
  const cities = Object.keys(cityMapping);
  const [data, setData] = useState<Record<string, any>>({});
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(false);

  const fetchAll = async () => {
    setError(false);
    try {
      const results = await Promise.all(
        cities.map(async (city) => [city, await fetchAirQuality(city)]),
      );
      setData(Object.fromEntries(results));
    } catch {
      setError(true);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchAll();
    const interval = setInterval(fetchAll, 30 * 1000); // refresh çdo 30 sekonda
    return () => clearInterval(interval);
  }, []);

  return { data, loading, error };
}
